from collections import defaultdict

class Solution(object):
    def countPairsOfConnectableServers(self, edges, signalSpeed):
        n = len(edges) + 1
        adj = defaultdict(list)
        for a, b, w in edges:
            adj[a].append((b, w))
            adj[b].append((a, w))
        def dfs(u, parent, dist):
            cnt = 1 if dist % signalSpeed == 0 else 0
            for v, w in adj[u]:
                if v != parent:
                    cnt += dfs(v, u, dist + w)
            return cnt
        result = [0] * n
        for root in range(n):
            subtree_counts = [dfs(v, root, w) for v, w in adj[root]]
            S = sum(subtree_counts)
            total = 0
            running = 0
            for c in subtree_counts:
                total += c * (S - running - c)
                running += c
            result[root] = total
        return result
